text:
This is a test of embedding a Shinylive app inside a Quarto page. The app below runs entirely in your browser — no server, no cold starts.
#| '!! shinylive warning !!': |
#|   shinylive does not work in self-contained HTML documents.
#|   Please set `embed-resources: false` in your metadata.
#| standalone: true
#| viewerHeight: 500

library(shiny)
library(leaflet)

ui &lt;- fluidPage(
  titlePanel("BHEI test map"),
  sidebarLayout(
    sidebarPanel(
      sliderInput("zoom", "Zoom level:", min = 8, max = 14, value = 10)
    ),
    mainPanel(
      leafletOutput("map", height = "400px")
    )
  )
)

server &lt;- function(input, output) {
  output$map &lt;- renderLeaflet({
    leaflet() |&gt;
      addTiles() |&gt;
      setView(lng = -117.15, lat = 32.72, zoom = input$zoom) |&gt;
      addMarkers(lng = -117.15, lat = 32.72, popup = "San Diego")
  })
}

shinyApp(ui, server)
